import { describe, expect, test } from 'bun:test';
import { buildProtocol69ProjectionEnvelope } from './protocol69';
import {
  buildR1ComputeReceipt,
  buildR1WorkStealClaim,
  buildR1WorkStealHint,
  buildR1WorkStealQueueSummary,
  buildR1WorkStealReceiptSubmission,
  validateR1ComputeReceipt,
  validateR1WorkStealClaim,
  validateR1WorkStealHint,
  validateR1WorkStealReceiptSubmission,
} from './protocol69-r1-worksteal';

describe('protocol69 R1 work-steal contracts', () => {
  test('builds non-executable deterministic fibonacci hints', () => {
    const hint = buildR1WorkStealHint({
      hintId: 'hint:fib:40',
      producerDeviceId: 'did:aeon:device:monster',
      targetPhyleId: 'phyle:r1-room',
      workKind: 'fibonacci',
      n: 40,
      priority: 7,
      ttlMs: 5_000,
      timestampMs: 69,
      witnessWindowHash: 'btle-window:abc',
    });

    expect(hint).toEqual(
      expect.objectContaining({
        schemaVersion: 'gnosis.protocol69.r1-worksteal-hint.v1',
        contractId: 'gnosis.protocol69.r1-worksteal.deterministic-fib-hint.v1',
        theoremId:
          'FoilLoserPolicy.r1_idle_witness_may_try_deterministic_work_hint',
        executable: false,
        workKind: 'fibonacci',
        n: 40,
        priority: 7,
      })
    );
    expect(hint.projection.expectedProjection).toBe(69);
  });

  test('builds compute receipts as reuse rights, not authority', () => {
    const receipt = buildR1ComputeReceipt({
      hintId: 'hint:fib:20',
      workerDeviceId: 'did:aeon:device:r1-a',
      targetPhyleId: 'phyle:r1-room',
      workKind: 'fibonacci',
      n: 20,
      result: '6765',
      resultDigest: 'sha256:6765',
      computeNs: 1_200,
      validationNs: 80,
      timestampMs: 70,
      beamCacheKey: 'beam:fib:20:6765',
      projection: buildProtocol69ProjectionEnvelope(),
    });

    expect(validateR1ComputeReceipt(receipt)).toEqual(
      expect.objectContaining({
        authority: 'reuse-right',
        executable: false,
        workerDeviceId: 'did:aeon:device:r1-a',
        result: '6765',
        beamCacheKey: 'beam:fib:20:6765',
      })
    );
  });

  test('builds small qwen-knot hints for cross-room validation', () => {
    const hint = buildR1WorkStealHint({
      hintId: 'hint:qwen-knot:tiny',
      producerDeviceId: 'did:aeon:device:monster',
      targetPhyleId: 'phyle:r1-room',
      workKind: 'qwen-knot',
      n: 0,
      modelId: 'qwen2.5-0.5b-instruct-q4',
      knotId: 'qwen-knot:tiny',
      knotHash: 'sha256:qwen-knot-tiny',
      tokenBudget: 128,
      ttlMs: 5_000,
      timestampMs: 71,
    });

    expect(validateR1WorkStealHint(hint)).toEqual(
      expect.objectContaining({
        workKind: 'qwen-knot',
        modelId: 'qwen2.5-0.5b-instruct-q4',
        knotId: 'qwen-knot:tiny',
        knotHash: 'sha256:qwen-knot-tiny',
        tokenBudget: 128,
        executable: false,
      })
    );
  });

  test('rejects qwen-knot hints without a bounded knot descriptor', () => {
    expect(() =>
      buildR1WorkStealHint({
        hintId: 'hint:qwen-knot:bad',
        producerDeviceId: 'did:aeon:device:monster',
        targetPhyleId: 'phyle:r1-room',
        workKind: 'qwen-knot',
        n: 0,
        ttlMs: 5_000,
        timestampMs: 71,
      })
    ).toThrow(/qwen-knot/);
  });

  test('rejects malformed hints and projection drift', () => {
    expect(() =>
      validateR1WorkStealHint({
        ...buildR1WorkStealHint({
          hintId: 'hint:fib:20',
          producerDeviceId: 'did:aeon:device:monster',
          targetPhyleId: 'phyle:r1-room',
          workKind: 'fibonacci',
          n: 20,
          ttlMs: 1_000,
          timestampMs: 1,
        }),
        executable: true,
      })
    ).toThrow(/non-executable/);

    expect(() =>
      validateR1ComputeReceipt({
        ...buildR1ComputeReceipt({
          hintId: 'hint:fib:20',
          workerDeviceId: 'did:aeon:device:r1',
          targetPhyleId: 'phyle:r1-room',
          workKind: 'fibonacci',
          n: 20,
          result: '6765',
          resultDigest: 'sha256:6765',
          computeNs: 1,
          validationNs: 1,
          timestampMs: 1,
          beamCacheKey: 'beam:fib:20:6765',
        }),
        projection: {
          ...buildProtocol69ProjectionEnvelope(),
          expectedProjection: 68,
        },
      })
    ).toThrow(/projection/);
  });

  test('builds queue claims and receipt submissions for resident workers', () => {
    const hint = buildR1WorkStealHint({
      hintId: 'hint:fib:21',
      producerDeviceId: 'did:aeon:device:monster',
      targetPhyleId: 'phyle:r1-room',
      workKind: 'fibonacci',
      n: 21,
      ttlMs: 5_000,
      timestampMs: 100,
    });
    const summary = buildR1WorkStealQueueSummary({
      pending: 1,
      claimed: 1,
      accepted: 0,
      rejected: 0,
      timestampMs: 101,
      perPhyle: [
        {
          phyleId: 'phyle:r1-room',
          pending: 1,
          claimed: 1,
          accepted: 0,
          rejected: 0,
          completedUnits: 0,
        },
      ],
    });

    const claim = buildR1WorkStealClaim({
      status: 'claimed',
      claimId: 'claim:r1-a:hint:fib:21',
      workerDeviceId: 'did:aeon:device:r1-a',
      phyleId: 'phyle:r1-room',
      hint,
      summary,
      timestampMs: 102,
    });

    expect(validateR1WorkStealClaim(claim)).toEqual(
      expect.objectContaining({
        executable: false,
        status: 'claimed',
        claimId: 'claim:r1-a:hint:fib:21',
      })
    );

    const receipt = buildR1ComputeReceipt({
      hintId: hint.hintId,
      workerDeviceId: 'did:aeon:device:r1-a',
      targetPhyleId: 'phyle:r1-room',
      workKind: 'fibonacci',
      n: 21,
      result: '10946',
      resultDigest: 'sha256:10946',
      computeNs: 100,
      validationNs: 10,
      timestampMs: 103,
      beamCacheKey: 'beam:fib:21:10946',
    });
    const submission = buildR1WorkStealReceiptSubmission({
      claimId: claim.claimId,
      receipt,
      timestampMs: 104,
    });

    expect(validateR1WorkStealReceiptSubmission(submission)).toEqual(
      expect.objectContaining({
        executable: false,
        claimId: 'claim:r1-a:hint:fib:21',
        receipt: expect.objectContaining({ authority: 'reuse-right' }),
      })
    );
  });

  test('rejects malformed resident queue envelopes', () => {
    const summary = buildR1WorkStealQueueSummary({
      pending: 0,
      claimed: 0,
      accepted: 0,
      rejected: 0,
      perPhyle: [],
      timestampMs: 1,
    });

    expect(() =>
      buildR1WorkStealClaim({
        status: 'claimed',
        workerDeviceId: 'did:aeon:device:r1-a',
        phyleId: 'phyle:r1-room',
        summary,
        timestampMs: 1,
      })
    ).toThrow(/claimId and hint/);

    expect(() =>
      validateR1WorkStealReceiptSubmission({
        ...buildR1WorkStealReceiptSubmission({
          claimId: 'claim:r1-a:1',
          receipt: buildR1ComputeReceipt({
            hintId: 'hint:fib:1',
            workerDeviceId: 'did:aeon:device:r1-a',
            targetPhyleId: 'phyle:r1-room',
            workKind: 'fibonacci',
            n: 1,
            result: '1',
            resultDigest: 'sha256:1',
            computeNs: 1,
            validationNs: 1,
            timestampMs: 1,
            beamCacheKey: 'beam:fib:1:1',
          }),
          timestampMs: 1,
        }),
        projection: {
          ...buildProtocol69ProjectionEnvelope(),
          expectedProjection: 68,
        },
      })
    ).toThrow(/projection/);
  });

  test('accepts null optional fields from Rust JSON wire output', () => {
    const hint = buildR1WorkStealHint({
      hintId: 'hint:fib:null-optionals',
      producerDeviceId: 'did:aeon:device:monster',
      targetPhyleId: 'phyle:r1-room',
      workKind: 'fibonacci',
      n: 8,
      ttlMs: 1_000,
      timestampMs: 1,
    });

    expect(
      validateR1WorkStealHint({
        ...hint,
        modelId: null,
        knotId: null,
        knotHash: null,
        tokenBudget: null,
        priority: null,
        witnessWindowHash: null,
      })
    ).toEqual(hint);
  });
});
